  1	import * as _ from 'lodash';
  2	import * as React from 'react';
  3	import {
  4	  Dropdown,
  5	  DropdownItem,
  6	  DropdownList,
  7	  MenuToggle,
  8	  MenuToggleElement,
  9	} from '@patternfly/react-core';
 10	import { alphanumericCompare } from './utils';
 11	import { useTranslation } from 'react-i18next';
 12	
 13	import './PipelinesOverview.scss';
 14	import {
 15	  useFlag,
 16	  useK8sWatchResource,
 17	} from '@openshift-console/dynamic-plugin-sdk';
 18	import { Project } from '../../types/openshift';
 19	import { ALL_NAMESPACES_KEY } from '../../consts';
 20	import { FLAGS } from '../../types';
 21	
 22	interface NameSpaceDropdownProps {
 23	  selected: string;
 24	  setSelected: (n: string) => void;
 25	}
 26	
 27	const NameSpaceDropdown: React.FC<NameSpaceDropdownProps> = ({
 28	  selected,
 29	  setSelected,
 30	}) => {
 31	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 32	  const [isOpen, setValue] = React.useState(false);
 33	  const canListNS = useFlag(FLAGS.CAN_LIST_NS);
 34	  const toggleIsOpen = React.useCallback(() => setValue((v) => !v), []);
 35	  const setClosed = React.useCallback(() => setValue(false), []);
 36	
 37	  const [projects, projectsLoaded] = useK8sWatchResource<Project[]>({
 38	    isList: true,
 39	    kind: 'Project',
 40	    optional: true,
 41	  });
 42	
 43	  const allNamespacesTitle = t('All');
 44	
 45	  const optionItems = React.useMemo(() => {
 46	    if (!projectsLoaded) {
 47	      return [];
 48	    }
 49	    const items = projects.map((item) => {
 50	      const { name } = item.metadata;
 51	      return { title: name, key: name };
 52	    });
 53	
 54	    if (
 55	      !items.some((option) => option.title === selected) &&
 56	      selected !== ALL_NAMESPACES_KEY
 57	    ) {
 58	      items.push({ title: selected, key: selected }); // Add current namespace if it isn't included
 59	    }
 60	    items.sort((a, b) => alphanumericCompare(a.title, b.title));
 61	    if (canListNS) {
 62	      items.unshift({ title: allNamespacesTitle, key: ALL_NAMESPACES_KEY });
 63	    }
 64	    return items;
 65	  }, [projects, projectsLoaded]);
 66	
 67	  return (
 68	    <>
 69	      <label className="project-dropdown-label">{t('Project')}</label>
 70	      <Dropdown
 71	        isOpen={isOpen}
 72	        onOpenChange={(isOpen: boolean) => setValue(isOpen)}
 73	        onSelect={setClosed}
 74	        toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
 75	          <MenuToggle
 76	            ref={toggleRef}
 77	            onClick={toggleIsOpen}
 78	            isExpanded={isOpen}
 79	          >
 80	            {selected !== ALL_NAMESPACES_KEY ? selected : allNamespacesTitle}
 81	          </MenuToggle>
 82	        )}
 83	        className="pipeline-overview__variable-dropdown"
 84	        isScrollable
 85	      >
 86	        <DropdownList>
 87	          {_.map(optionItems, (name, key) => (
 88	            <DropdownItem
 89	              component="button"
 90	              key={key}
 91	              onClick={() => setSelected(name.key)}
 92	              className={'max-height-menu'}
 93	            >
 94	              {name.title}
 95	            </DropdownItem>
 96	          ))}
 97	        </DropdownList>
 98	      </Dropdown>
 99	    </>
100	  );
101	};
102	
103	export default NameSpaceDropdown;

